import{_ as l,c as i,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const m=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/AI工具/pi-mono-AI工具.md","filePath":"github汇总/AI工具/pi-mono-AI工具.md"}'),o={name:"github汇总/AI工具/pi-mono-AI工具.md"};function h(n,a,d,t,c,p){return e(),i("div",null,a[0]||(a[0]=[r('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>pi-mono</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>Mario Zechner（badlogic）</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>AI工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>开发AI智能体时需要对接多个LLM提供商，管理复杂；缺少统一的智能体运行时、UI组件等基础设施，开发效率低。</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><p>构建AI智能体和管理LLM部署的工具包，以Monorepo形式包含统一多提供商LLM API、智能体运行时、终端UI等七个包。</p><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ol><li>统一的多提供商LLM API，一套代码可调用20多个大模型</li><li>智能体运行时支持工具调用和状态管理</li><li>提供交互式编程智能体命令行工具</li><li>包含终端UI库和Web组件，快速构建界面</li><li>提供管理vLLM部署的CLI工具</li><li>Monorepo结构，七个实用包打包在一起</li></ol><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/badlogic/pi-mono" target="_blank" rel="noreferrer">https://github.com/badlogic/pi-mono</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>适用于AI智能体开发者、LLM应用开发者，需要Node.js和npm环境。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><ol><li>检查Node.js和npm是否安装： <ul><li>执行位置：本机终端</li><li>完整命令：<code>node -v &amp;&amp; npm -v</code></li><li>成功标志：显示Node.js和npm版本号</li><li>失败处理：安装Node.js和npm</li></ul></li></ol><h2 id="主路径-安装与启动" tabindex="-1">主路径：安装与启动 <a class="header-anchor" href="#主路径-安装与启动" aria-label="Permalink to “主路径：安装与启动”">​</a></h2><h3 id="步骤1-克隆仓库" tabindex="-1">步骤1：克隆仓库 <a class="header-anchor" href="#步骤1-克隆仓库" aria-label="Permalink to “步骤1：克隆仓库”">​</a></h3><ul><li>步骤目标：获取项目代码</li><li>执行位置：项目目录</li><li>完整命令：<code>git clone https://github.com/badlogic/pi-mono.git &amp;&amp; cd pi-mono</code></li><li>成功标志：仓库克隆成功，进入项目目录</li><li>失败处理：检查网络连接，确认GitHub地址正确</li></ul><h3 id="步骤2-安装依赖" tabindex="-1">步骤2：安装依赖 <a class="header-anchor" href="#步骤2-安装依赖" aria-label="Permalink to “步骤2：安装依赖”">​</a></h3><ul><li>步骤目标：安装项目所有依赖</li><li>执行位置：项目根目录</li><li>完整命令：<code>npm install</code></li><li>成功标志：依赖安装完成</li><li>失败处理：检查网络连接，尝试使用淘宝镜像</li></ul><h3 id="步骤3-构建项目" tabindex="-1">步骤3：构建项目 <a class="header-anchor" href="#步骤3-构建项目" aria-label="Permalink to “步骤3：构建项目”">​</a></h3><ul><li>步骤目标：构建所有包</li><li>执行位置：项目根目录</li><li>完整命令：<code>npm run build</code></li><li>成功标志：构建完成，无错误</li><li>失败处理：检查Node.js版本是否符合要求</li></ul><h3 id="步骤4-代码检查" tabindex="-1">步骤4：代码检查 <a class="header-anchor" href="#步骤4-代码检查" aria-label="Permalink to “步骤4：代码检查”">​</a></h3><ul><li>步骤目标：执行lint、格式化和类型检查</li><li>执行位置：项目根目录</li><li>完整命令：<code>npm run check</code></li><li>成功标志：检查通过，无错误</li><li>失败处理：根据错误提示修复问题（注意npm run check需要先执行npm run build）</li></ul><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><ol><li>访问方式：终端命令</li><li>检查命令：<code>./pi-test.sh</code>（从源码运行pi，必须在仓库根目录执行）</li><li>预期返回：pi正常运行</li><li>页面特征（如适用）：无</li></ol><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p>现象：npm run check失败</p><ul><li>可能原因：未先执行npm run build</li><li>解决步骤：先运行npm run build，再运行npm run check</li></ul></li><li><p>现象：依赖安装失败</p><ul><li>可能原因：网络问题或npm镜像问题</li><li>解决步骤：尝试使用淘宝npm镜像或检查网络连接</li></ul></li><li><p>现象：构建失败</p><ul><li>可能原因：Node.js版本不兼容</li><li>解决步骤：检查Node.js版本，升级到推荐版本</li></ul></li></ol><h2 id="备选部署路径" tabindex="-1">备选部署路径 <a class="header-anchor" href="#备选部署路径" aria-label="Permalink to “备选部署路径”">​</a></h2><ol><li>运行测试（跳过需要API密钥的LLM依赖测试）：<code>./test.sh</code></li></ol><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>README中提供了基本的开发安装步骤，但各包的详细使用教程需要参考各包的具体文档。</p>',38)]))}const b=l(o,[["render",h]]);export{m as __pageData,b as default};
